#!/usr/bin/env python3
"""Run on RockPi from ros_ws: python3 scripts/install_llm_intent_board.py"""
import base64
from pathlib import Path

B64 = """"""

def main() -> None:
    root = Path(__file__).resolve().parent.parent
    dst = root / "voice_nav" / "llm_intent.py"
    bak = dst.with_suffix(".py.bak")
    if dst.exists():
        bak.write_bytes(dst.read_bytes())
        print("backup:", bak)
    dst.write_bytes(base64.b64decode(B64))
    import py_compile
    py_compile.compile(str(dst), doraise=True)
    print("written:", dst)
    print("syntax OK")

if __name__ == "__main__":
    main()
